from collections import defaultdict, deque

def longest_unique_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)

    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def bfs(start):
        queue = deque([(start, -1, 0, set())])  # (current_node, parent_node, current_length, current_values)
        max_length = 0
        min_nodes = float('inf')

        while queue:
            node, parent, length, values = queue.popleft()
            current_values = values.copy()
            current_values.add(nums[node])

            if len(current_values) < len(values) + 1:  # Duplicate value found
                continue

            if length > max_length:
                max_length = length
                min_nodes = len(current_values)
            elif length == max_length:
                min_nodes = min(min_nodes, len(current_values))

            for neighbor in graph[node]:
                if neighbor != parent:
                    queue.append((neighbor, node, length + 1, current_values))

        return max_length, min_nodes if max_length > 0 else 0

    overall_max_length = 0
    overall_min_nodes = float('inf')

    for i in range(n):
        length, min_nodes = bfs(i)
        if length > overall_max_length:
            overall_max_length = length
            overall_min_nodes = min_nodes
        elif length == overall_max_length:
            overall_min_nodes = min(overall_min_nodes, min_nodes)

    return [overall_max_length, overall_min_nodes] if overall_max_length > 0 else [0, 0]

