from collections import defaultdict, deque

def longest_special_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)

    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def bfs(start):
        queue = deque([start])
        visited = {start}
        count = defaultdict(int)
        count[nums[start]] += 1
        max_length = 0
        min_nodes = float('inf')

        while queue:
            current_length = len(queue)
            for _ in range(current_length):
                node = queue.popleft()
                for neighbor in graph[node]:
                    if neighbor not in visited:
                        if count[nums[neighbor]] < 2:
                            visited.add(neighbor)
                            queue.append(neighbor)
                            count[nums[neighbor]] += 1

            if len(visited) > 0:
                max_length += current_length
                min_nodes = min(min_nodes, len(visited))

        return max_length, min_nodes if min_nodes != float('inf') else 0

    longest_path = 0
    min_nodes = float('inf')

    for i in range(n):
        if nums[i] not in nums[:i]:  # To avoid reprocessing nodes
            length, nodes = bfs(i)
            longest_path = max(longest_path, length)
            if length > 0:
                min_nodes = min(min_nodes, nodes)

    return [longest_path, min_nodes if min_nodes != float('inf') else 0]

