def longest_special_path(nums, edges):
    from collections import defaultdict, deque

    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    longest_length = 0
    min_nodes = float('inf')

    def bfs(start):
        nonlocal longest_length, min_nodes
        queue = deque([(start, -1, {}, 0)])  # (current_node, parent, count_map, current_length)
        while queue:
            node, parent, count_map, current_length = queue.popleft()
            count_map[nums[node]] = count_map.get(nums[node], 0) + 1

            if count_map[nums[node]] > 2:
                continue

            current_length += 1

            if current_length > longest_length:
                longest_length = current_length
                min_nodes = 1
            elif current_length == longest_length:
                min_nodes = min(min_nodes, 1)

            for neighbor in graph[node]:
                if neighbor != parent:
                    queue.append((neighbor, node, count_map.copy(), current_length))

    for i in range(n):
        bfs(i)

    return [longest_length, min_nodes] if longest_length > 0 else [0, 0]

