def find_longest_extra_path(nums, edges):
    from collections import defaultdict, deque

    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def is_valid_path(path):
        count = defaultdict(int)
        for node in path:
            count[nums[node]] += 1
            if count[nums[node]] > 2:
                return False
        return True

    longest_paths = []
    max_length = 0

    def bfs(start):
        nonlocal max_length
        queue = deque([(start, [start])])
        while queue:
            current, path = queue.popleft()
            if is_valid_path(path):
                if len(path) > max_length:
                    max_length = len(path)
                    longest_paths.clear()
                    longest_paths.append(path)
                elif len(path) == max_length:
                    longest_paths.append(path)
                for neighbor in graph[current]:
                    if neighbor not in path:
                        queue.append((neighbor, path + [neighbor]))

    for i in range(len(nums)):
        bfs(i)

    if longest_paths:
        return [max_length, min(len(path) for path in longest_paths)]
    else:
        return [0, 0]

