def find_longest_unique_path(nums, edges):
    from collections import defaultdict, deque

    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def bfs(start):
        queue = deque([(start, [start], nums[start])])
        longest_path = []
        min_guests = float('inf')

        while queue:
            node, path, total_value = queue.popleft()
            if total_value > 2 * nums[node]:
                continue

            if len(path) > len(longest_path):
                longest_path = path
                min_guests = len(path)
            elif len(path) == len(longest_path):
                min_guests = min(min_guests, len(path))

            for neighbor in graph[node]:
                if neighbor not in path:
                    queue.append((neighbor, path + [neighbor], total_value + nums[neighbor]))

        return longest_path, min_guests

    overall_longest_path = []
    overall_min_guests = float('inf')

    for i in range(len(nums)):
        path, min_guests = bfs(i)
        if len(path) > len(overall_longest_path):
            overall_longest_path = path
            overall_min_guests = min_guests
        elif len(path) == len(overall_longest_path):
            overall_min_guests = min(overall_min_guests, min_guests)

    if not overall_longest_path:
        return [0, 0]

    return [len(overall_longest_path), overall_min_guests]

def find_special_path(nums, edges):
    from collections import defaultdict, deque

    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    n = len(nums)
    max_distance = 0
    min_guests = float('inf')

    def bfs(start):
        nonlocal max_distance, min_guests
        queue = deque([(start, nums[start], 0)])  # (current_node, current_value, current_distance)
        visited = {start: (nums[start], 0)}  # node: (last_value, distance)

        while queue:
            node, last_value, distance = queue.popleft()

            for neighbor in graph[node]:
                if neighbor not in visited:
                    if nums[neighbor] <= 2 * last_value:
                        new_distance = distance + 1
                        visited[neighbor] = (nums[neighbor], new_distance)
                        queue.append((neighbor, nums[neighbor], new_distance))
                        if new_distance > max_distance:
                            max_distance = new_distance
                            min_guests = 1
                        elif new_distance == max_distance:
                            min_guests += 1

    for i in range(n):
        bfs(i)

    if max_distance == 0:
        return [0, 0]
    return [max_distance, min_guests]

